import pytest
from stringkit import reverse, count_vowels, title_case, starts_with_vowel


class TestReverse:
    def test_empty_string(self):
        assert reverse("") == ""

    def test_single_character(self):
        assert reverse("a") == "a"

    def test_palindrome(self):
        assert reverse("racecar") == "racecar"

    def test_normal_string(self):
        assert reverse("hello") == "olleh"

    def test_with_spaces(self):
        assert reverse("a b c") == "c b a"

    def test_unicode(self):
        assert reverse("café") == "éfac"


class TestCountVowels:
    def test_empty_string(self):
        assert count_vowels("") == 0

    def test_no_vowels(self):
        assert count_vowels("xyz") == 0

    def test_all_vowels(self):
        assert count_vowels("aeiou") == 5

    def test_mixed_case(self):
        assert count_vowels("AbEcIdOfU") == 5

    def test_with_consonants(self):
        assert count_vowels("hello world") == 3

    @pytest.mark.parametrize("text,expected", [
        ("", 0),
        ("a", 1),
        ("b", 0),
        ("AEIOU", 5),
        ("Python", 1),
    ])
    def test_parametrized(self, text, expected):
        assert count_vowels(text) == expected


class TestTitleCase:
    def test_empty_string(self):
        assert title_case("") == ""

    def test_single_word(self):
        assert title_case("hello") == "Hello"

    def test_multiple_words(self):
        assert title_case("hello world") == "Hello World"

    def test_already_title_case(self):
        assert title_case("Hello World") == "Hello World"

    def test_mixed_case(self):
        assert title_case("hELLO wORLD") == "Hello World"

    def test_with_extra_spaces(self):
        assert title_case("  hello   world  ") == "Hello World"

    def test_single_letter_words(self):
        assert title_case("a b c") == "A B C"


class TestStartsWithVowel:
    def test_empty_string(self):
        assert starts_with_vowel("") is False

    def test_starts_with_vowel_lowercase(self):
        assert starts_with_vowel("apple") is True

    def test_starts_with_vowel_uppercase(self):
        assert starts_with_vowel("Apple") is True

    def test_starts_with_consonant(self):
        assert starts_with_vowel("banana") is False

    def test_single_vowel(self):
        assert starts_with_vowel("a") is True

    def test_single_consonant(self):
        assert starts_with_vowel("b") is False

    @pytest.mark.parametrize("word,expected", [
        ("", False),
        ("a", True),
        ("E", True),
        ("i", True),
        ("O", True),
        ("u", True),
        ("y", False),
        ("Y", False),
    ])
    def test_parametrized(self, word, expected):
        assert starts_with_vowel(word) == expected

